uv_x = 1.0 - abs( fract( uv_x * 0.5 ) * 2.0 - 1.0 ); // Eo.S' mirror code
uv_x = 0.5 + (uv_x-0.5)*vec2(0.75,-0.9) - vec2(0,0.05);

